PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE _mocha_migrations (
number     INTEGER UNIQUE,
up_sql     TEXT NOT NULL,
down_sql   TEXT NOT NULL,
applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(1,replace('\nCREATE TABLE campaigns (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  title TEXT NOT NULL,\n  short_description TEXT NOT NULL,\n  full_description TEXT NOT NULL,\n  image_url TEXT NOT NULL,\n  category TEXT NOT NULL,\n  goal_amount REAL NOT NULL,\n  current_amount REAL DEFAULT 0,\n  backers_count INTEGER DEFAULT 0,\n  end_date DATE NOT NULL,\n  creator_name TEXT NOT NULL,\n  creator_email TEXT,\n  creator_avatar TEXT,\n  is_featured BOOLEAN DEFAULT 0,\n  status TEXT DEFAULT ''active'',\n  risks TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_campaigns_category ON campaigns(category);\nCREATE INDEX idx_campaigns_status ON campaigns(status);\nCREATE INDEX idx_campaigns_featured ON campaigns(is_featured);\n','\n',char(10)),replace('\nDROP INDEX idx_campaigns_featured;\nDROP INDEX idx_campaigns_status;\nDROP INDEX idx_campaigns_category;\nDROP TABLE campaigns;\n','\n',char(10)),'2026-02-12 21:47:48');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(2,replace('\nCREATE TABLE rewards (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  campaign_id INTEGER NOT NULL,\n  title TEXT NOT NULL,\n  description TEXT NOT NULL,\n  min_amount REAL NOT NULL,\n  estimated_delivery TEXT NOT NULL,\n  items_included TEXT NOT NULL,\n  limited_quantity INTEGER,\n  claimed_count INTEGER DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_rewards_campaign ON rewards(campaign_id);\n','\n',char(10)),replace('\nDROP INDEX idx_rewards_campaign;\nDROP TABLE rewards;\n','\n',char(10)),'2026-02-12 21:47:48');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(3,replace('\nCREATE TABLE pledges (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  campaign_id INTEGER NOT NULL,\n  reward_id INTEGER,\n  amount REAL NOT NULL,\n  backer_name TEXT NOT NULL,\n  backer_email TEXT NOT NULL,\n  status TEXT DEFAULT ''pending'',\n  payment_id TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_pledges_campaign ON pledges(campaign_id);\nCREATE INDEX idx_pledges_reward ON pledges(reward_id);\nCREATE INDEX idx_pledges_email ON pledges(backer_email);\n','\n',char(10)),replace('\nDROP INDEX idx_pledges_email;\nDROP INDEX idx_pledges_reward;\nDROP INDEX idx_pledges_campaign;\nDROP TABLE pledges;\n','\n',char(10)),'2026-02-12 21:47:48');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(4,replace('\nCREATE TABLE campaign_updates (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  campaign_id INTEGER NOT NULL,\n  title TEXT NOT NULL,\n  content TEXT NOT NULL,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_updates_campaign ON campaign_updates(campaign_id);\n','\n',char(10)),replace('\nDROP INDEX idx_updates_campaign;\nDROP TABLE campaign_updates;\n','\n',char(10)),'2026-02-12 21:47:48');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(5,replace('\nCREATE TABLE campaign_faqs (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  campaign_id INTEGER NOT NULL,\n  question TEXT NOT NULL,\n  answer TEXT NOT NULL,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_faqs_campaign ON campaign_faqs(campaign_id);\n','\n',char(10)),replace('\nDROP INDEX idx_faqs_campaign;\nDROP TABLE campaign_faqs;\n','\n',char(10)),'2026-02-12 21:47:48');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(6,replace('\n-- Sample Campaigns\nINSERT INTO campaigns (title, short_description, full_description, image_url, category, goal_amount, current_amount, backers_count, end_date, status, is_featured, creator_name, creator_email, creator_avatar, risks)\nVALUES \n(\n  ''EcoBottle - Garrafa que Purifica Água'',\n  ''Uma garrafa inteligente com filtro UV que purifica qualquer água em segundos. Sustentável e perfeita para aventuras.'',\n  ''A EcoBottle é uma revolução em hidratação sustentável. Com tecnologia UV-C integrada, ela elimina 99.9% das bactérias e vírus em apenas 60 segundos. Feita com materiais reciclados e totalmente livre de BPA, nossa garrafa é perfeita para trilhas, viagens e uso diário.\n\n## Por que EcoBottle?\n\n- **Tecnologia UV-C**: Purificação em 60 segundos\n- **Material Sustentável**: 100% reciclável\n- **Bateria Duradoura**: Até 40 ciclos por carga\n- **Design Premiado**: Ergonômico e elegante\n\nNossa equipe trabalhou por 2 anos desenvolvendo o melhor sistema de purificação portátil do mercado. Junte-se a nós nessa jornada!'',\n  ''https://images.unsplash.com/photo-1602143407151-7111542de6e8?w=800'',\n  ''Tecnologia'',\n  75000,\n  52340,\n  127,\n  date(''now'', ''+25 days''),\n  ''active'',\n  1,\n  ''Marina Santos'',\n  ''marina@ecobottle.com'',\n  ''https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=150'',\n  ''O principal risco é o prazo de entrega dos componentes eletrônicos. Estamos trabalhando com fornecedores confiáveis e temos estoque reserva para mitigar atrasos.''\n),\n(\n  ''Café Origem - Grãos Especiais da Serra'',\n  ''Cafés especiais de pequenos produtores da Serra da Mantiqueira, torrados artesanalmente e entregues frescos.'',\n  ''Somos apaixonados por café e queremos conectar você diretamente aos melhores produtores da Serra da Mantiqueira. Cada pacote conta uma história e apoia famílias que cultivam café há gerações.\n\n## Nossa Missão\n\nLevar o melhor café brasileiro direto do produtor para sua xícara, garantindo:\n\n- **Qualidade Premium**: Grãos acima de 84 pontos SCA\n- **Comércio Justo**: Preço justo aos produtores\n- **Frescor Garantido**: Torrado sob demanda\n- **Rastreabilidade**: Saiba exatamente de onde vem seu café\n\nCom seu apoio, vamos expandir nossa rede de produtores parceiros e levar esse sabor único para mais pessoas.'',\n  ''https://images.unsplash.com/photo-1447933601403-0c6688de566e?w=800'',\n  ''Comida'',\n  25000,\n  31250,\n  89,\n  date(''now'', ''+18 days''),\n  ''active'',\n  1,\n  ''Pedro Oliveira'',\n  ''pedro@cafeorigem.com'',\n  ''https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=150'',\n  ''Safras podem variar conforme clima. Trabalhamos com múltiplos produtores para garantir fornecimento constante.''\n),\n(\n  ''Luminária Artesanal em Madeira'',\n  ''Luminárias únicas feitas à mão com madeira de reflorestamento. Design minimalista que transforma qualquer ambiente.'',\n  ''Cada luminária é uma obra de arte única, esculpida à mão por artesãos locais usando madeira de reflorestamento certificada.\n\n## Características\n\n- **Madeira Certificada**: Origem sustentável garantida\n- **Feito à Mão**: Cada peça é única\n- **LED Integrado**: Econômico e durável\n- **Design Atemporal**: Combina com qualquer decoração\n\nNosso projeto apoia comunidades locais e promove o artesanato brasileiro de qualidade.'',\n  ''https://images.unsplash.com/photo-1507473885765-e6ed057f782c?w=800'',\n  ''Arte'',\n  15000,\n  8750,\n  34,\n  date(''now'', ''+40 days''),\n  ''active'',\n  0,\n  ''Ana Ferreira'',\n  ''ana@lumiart.com'',\n  ''https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=150'',\n  ''Por ser artesanal, pequenas variações são esperadas. Cada peça passa por controle de qualidade rigoroso.''\n),\n(\n  ''App de Meditação para Crianças'',\n  ''Um aplicativo lúdico que ensina mindfulness para crianças de 4 a 12 anos através de histórias e jogos interativos.'',\n  ''ZenKids é um app de meditação criado especialmente para crianças, com personagens adoráveis e histórias envolventes que ensinam técnicas de respiração, relaxamento e foco.\n\n## Funcionalidades\n\n- **Histórias Guiadas**: Meditações em formato de aventura\n- **Jogos de Respiração**: Aprenda brincando\n- **Modo Família**: Até 4 perfis por conta\n- **Sem Anúncios**: Experiência 100% segura\n- **Offline**: Use em qualquer lugar\n\nDesenvolvido com apoio de psicólogos infantis e pedagogos.'',\n  ''https://images.unsplash.com/photo-1503454537195-1dcabb73ffb9?w=800'',\n  ''Tecnologia'',\n  50000,\n  12500,\n  56,\n  date(''now'', ''+35 days''),\n  ''active'',\n  0,\n  ''Carla Mendes'',\n  ''carla@zenkids.app'',\n  ''https://images.unsplash.com/photo-1580489944761-15a19d654956?w=150'',\n  ''Desenvolvimento de software pode ter ajustes de cronograma. Manteremos todos atualizados sobre o progresso.''\n),\n(\n  ''Documentário: Povos da Floresta'',\n  ''Um documentário sobre as comunidades tradicionais da Amazônia e sua luta pela preservação da floresta.'',\n  ''Este documentário vai contar as histórias de 5 comunidades tradicionais da Amazônia brasileira, mostrando sua cultura, desafios e a importância vital da preservação da floresta.\n\n## O Projeto\n\n- **12 meses de filmagem** em locações remotas\n- **5 comunidades** retratadas\n- **Equipe premiada** de documentaristas\n- **Distribuição** em festivais internacionais\n\n10% da arrecadação será doado diretamente às comunidades filmadas.'',\n  ''https://images.unsplash.com/photo-1516026672322-bc52d61a55d5?w=800'',\n  ''Filme'',\n  120000,\n  45000,\n  156,\n  date(''now'', ''+60 days''),\n  ''active'',\n  0,\n  ''Ricardo Lima'',\n  ''ricardo@docfloresta.com'',\n  ''https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=150'',\n  ''Filmagens em áreas remotas dependem de condições climáticas e logísticas. Temos cronograma flexível para acomodar imprevistos.''\n),\n(\n  ''Mochila Solar para Nômades Digitais'',\n  ''Mochila com painel solar integrado, compartimentos inteligentes e porta USB para carregar seus dispositivos em qualquer lugar.'',\n  ''A NomadPack é a mochila definitiva para quem trabalha de qualquer lugar. Com painel solar de alta eficiência e design ergonômico, você nunca mais fica sem bateria.\n\n## Especificações\n\n- **Painel Solar 10W**: Carrega smartphone em 3h\n- **Powerbank 20000mAh**: Incluído\n- **Compartimento Laptop**: Até 17 polegadas\n- **Impermeável**: Material resistente à água\n- **Antifurto**: Bolsos ocultos e zíperes de segurança\n\nPerfeita para viagens, trilhas e o dia a dia urbano.'',\n  ''https://images.unsplash.com/photo-1553062407-98eeb64c6a62?w=800'',\n  ''Tecnologia'',\n  40000,\n  42800,\n  98,\n  date(''now'', ''+12 days''),\n  ''active'',\n  1,\n  ''Lucas Andrade'',\n  ''lucas@nomadpack.com'',\n  ''https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=150'',\n  ''Produção na China pode sofrer atrasos logísticos. Temos margem de segurança no cronograma.''\n);\n\n-- Rewards for EcoBottle (campaign 1)\nINSERT INTO rewards (campaign_id, title, description, min_amount, estimated_delivery, items_included, limited_quantity, claimed_count)\nVALUES \n(1, ''Early Bird'', ''Seja um dos primeiros! EcoBottle com 40% de desconto'', 149, ''Março 2025'', ''["1x EcoBottle (500ml)", "1x Capa protetora"]'', 100, 67),\n(1, ''Kit Duplo'', ''Duas EcoBottles para você e alguém especial'', 269, ''Março 2025'', ''["2x EcoBottle (500ml)", "2x Capa protetora", "1x Kit de limpeza"]'', 50, 28),\n(1, ''Kit Família'', ''Pack completo para toda a família'', 449, ''Abril 2025'', ''["4x EcoBottle (500ml)", "4x Capa protetora", "1x Carregador múltiplo", "1x Kit de limpeza premium"]'', 30, 12);\n\n-- Rewards for Café Origem (campaign 2)\nINSERT INTO rewards (campaign_id, title, description, min_amount, estimated_delivery, items_included, limited_quantity, claimed_count)\nVALUES \n(2, ''Degustação'', ''3 pacotes de 250g de cafés diferentes'', 89, ''Fevereiro 2025'', ''["3x Café 250g (origens variadas)", "1x Cartão com história dos produtores"]'', NULL, 45),\n(2, ''Assinatura Mensal'', ''6 meses de café fresco entregue em casa'', 299, ''Fevereiro 2025'', ''["6x Entregas mensais de 500g", "1x Caneca exclusiva", "Acesso ao clube de membros"]'', 50, 31),\n(2, ''Experiência Completa'', ''Visita à fazenda + 1 ano de café'', 799, ''Março 2025'', ''["12x Entregas mensais de 500g", "1x Visita guiada à fazenda", "1x Kit barista completo", "Nome gravado em quadro de apoiadores"]'', 10, 8);\n\n-- Rewards for Luminária (campaign 3)\nINSERT INTO rewards (campaign_id, title, description, min_amount, estimated_delivery, items_included, limited_quantity, claimed_count)\nVALUES \n(3, ''Luminária Mesa'', ''Luminária de mesa em madeira de lei'', 189, ''Abril 2025'', ''["1x Luminária de mesa", "1x Lâmpada LED", "Certificado de autenticidade"]'', 40, 22),\n(3, ''Luminária Pendente'', ''Luminária pendente para teto'', 289, ''Abril 2025'', ''["1x Luminária pendente", "1x Kit instalação", "1x Lâmpada LED", "Certificado de autenticidade"]'', 30, 8),\n(3, ''Conjunto Exclusivo'', ''Mesa + Pendente combinando'', 429, ''Maio 2025'', ''["1x Luminária de mesa", "1x Luminária pendente", "2x Lâmpadas LED", "Certificado de autenticidade", "Nome na peça"]'', 15, 4);\n\n-- Rewards for ZenKids (campaign 4)\nINSERT INTO rewards (campaign_id, title, description, min_amount, estimated_delivery, items_included, limited_quantity, claimed_count)\nVALUES \n(4, ''Acesso Vitalício'', ''Assinatura lifetime do app'', 79, ''Janeiro 2025'', ''["Acesso vitalício ao app", "Todas as atualizações futuras"]'', NULL, 42),\n(4, ''Kit Família'', ''Acesso para toda família + brindes'', 149, ''Janeiro 2025'', ''["Acesso vitalício (4 perfis)", "1x Livro de atividades físico", "1x Pelúcia do mascote"]'', 100, 12),\n(4, ''Patrocinador'', ''Seu nome nos créditos + benefícios'', 499, ''Janeiro 2025'', ''["Acesso vitalício", "Nome nos créditos do app", "1x Call com a equipe", "Kit completo de brindes"]'', 20, 2);\n\n-- Rewards for Documentary (campaign 5)\nINSERT INTO rewards (campaign_id, title, description, min_amount, estimated_delivery, items_included, limited_quantity, claimed_count)\nVALUES \n(5, ''Apoiador Digital'', ''Acesso antecipado ao documentário'', 45, ''Dezembro 2025'', ''["Link exclusivo de acesso", "Making of digital"]'', NULL, 89),\n(5, ''Colecionador'', ''Blu-ray + pôster autografado'', 149, ''Janeiro 2026'', ''["1x Blu-ray do documentário", "1x Pôster autografado", "Créditos como apoiador"]'', 200, 52),\n(5, ''Produtor Associado'', ''Crédito de produtor + pré-estreia'', 999, ''Dezembro 2025'', ''["Crédito de Produtor Associado", "2x Ingressos pré-estreia", "1x Blu-ray especial", "1x Livro de fotografias", "Agradecimento no site"]'', 25, 15);\n\n-- Rewards for NomadPack (campaign 6)\nINSERT INTO rewards (campaign_id, title, description, min_amount, estimated_delivery, items_included, limited_quantity, claimed_count)\nVALUES \n(6, ''Super Early Bird'', ''Mochila com 50% de desconto'', 299, ''Março 2025'', ''["1x NomadPack", "1x Powerbank 20000mAh", "1x Capa de chuva"]'', 50, 50),\n(6, ''Early Bird'', ''Mochila com 35% de desconto'', 349, ''Março 2025'', ''["1x NomadPack", "1x Powerbank 20000mAh", "1x Capa de chuva"]'', 100, 38),\n(6, ''Kit Completo'', ''Mochila + todos os acessórios'', 499, ''Abril 2025'', ''["1x NomadPack", "1x Powerbank 20000mAh", "1x Capa de chuva", "1x Organizador de cabos", "1x Necessaire tech", "1x Tag GPS"]'', 80, 10);\n\n-- Sample Pledges\nINSERT INTO pledges (campaign_id, reward_id, amount, backer_name, backer_email, status, created_at)\nVALUES \n(1, 1, 149, ''João Silva'', ''joao@email.com'', ''confirmed'', datetime(''now'', ''-3 days'')),\n(1, 2, 269, ''Maria Costa'', ''maria@email.com'', ''confirmed'', datetime(''now'', ''-2 days'')),\n(1, 1, 149, ''Carlos Souza'', ''carlos@email.com'', ''confirmed'', datetime(''now'', ''-1 day'')),\n(1, NULL, 50, ''Ana Paula'', ''ana@email.com'', ''confirmed'', datetime(''now'', ''-12 hours'')),\n(2, 1, 89, ''Roberto Almeida'', ''roberto@email.com'', ''confirmed'', datetime(''now'', ''-5 days'')),\n(2, 2, 350, ''Fernanda Lima'', ''fernanda@email.com'', ''confirmed'', datetime(''now'', ''-3 days'')),\n(2, 1, 100, ''Bruno Santos'', ''bruno@email.com'', ''confirmed'', datetime(''now'', ''-1 day'')),\n(3, 1, 189, ''Patricia Rocha'', ''patricia@email.com'', ''confirmed'', datetime(''now'', ''-4 days'')),\n(3, 3, 450, ''Marcelo Dias'', ''marcelo@email.com'', ''confirmed'', datetime(''now'', ''-2 days'')),\n(6, 2, 349, ''Juliana Melo'', ''juliana@email.com'', ''confirmed'', datetime(''now'', ''-6 hours'')),\n(6, 3, 499, ''Thiago Nunes'', ''thiago@email.com'', ''confirmed'', datetime(''now'', ''-2 hours''));\n\n-- Campaign Updates\nINSERT INTO campaign_updates (campaign_id, title, content, created_at)\nVALUES \n(1, ''Protótipo finalizado!'', ''Estamos muito felizes em anunciar que nosso protótipo final foi aprovado nos testes de qualidade! A produção em massa começa no próximo mês.'', datetime(''now'', ''-5 days'')),\n(1, ''Meta de 50% atingida!'', ''Obrigado a todos os 100+ apoiadores que já acreditaram no projeto. Estamos a caminho de realizar esse sonho!'', datetime(''now'', ''-2 days'')),\n(2, ''Nova parceria com produtores'', ''Fechamos parceria com mais 3 famílias produtoras de café especial. Isso significa mais variedade para vocês!'', datetime(''now'', ''-4 days'')),\n(6, ''Produção iniciada!'', ''As primeiras 200 unidades já entraram em produção. Fotos da fábrica em breve!'', datetime(''now'', ''-1 day''));\n\n-- Campaign FAQs\nINSERT INTO campaign_faqs (campaign_id, question, answer)\nVALUES \n(1, ''A EcoBottle é segura para crianças?'', ''Sim! Todos os materiais são atóxicos e a garrafa é livre de BPA. O sistema UV é ativado apenas com o botão pressionado por 3 segundos.''),\n(1, ''Posso usar com qualquer tipo de água?'', ''A EcoBottle purifica água potável de torneira, filtros e fontes naturais. Não é recomendada para água salgada ou com contaminação química.''),\n(1, ''Qual a garantia do produto?'', ''Oferecemos garantia de 2 anos contra defeitos de fabricação.''),\n(2, ''O café é orgânico?'', ''Trabalhamos com produtores que usam práticas sustentáveis. Alguns são certificados orgânicos, outros estão em processo de certificação.''),\n(2, ''Vocês entregam em todo Brasil?'', ''Sim! Entregamos para todo o território nacional via Correios ou transportadora.''),\n(6, ''O painel solar funciona em dias nublados?'', ''Sim, porém com eficiência reduzida (cerca de 30-40% da capacidade). O powerbank integrado garante que você sempre tenha energia reserva.''),\n(6, ''A mochila é aprovada como bagagem de mão?'', ''Sim! As dimensões (50x35x20cm) são compatíveis com a maioria das companhias aéreas.'');\n','\n',char(10)),replace('\nDELETE FROM campaign_faqs WHERE campaign_id IN (1, 2, 6);\nDELETE FROM campaign_updates WHERE campaign_id IN (1, 2, 6);\nDELETE FROM pledges WHERE campaign_id IN (1, 2, 3, 6);\nDELETE FROM rewards WHERE campaign_id IN (1, 2, 3, 4, 5, 6);\nDELETE FROM campaigns WHERE id IN (1, 2, 3, 4, 5, 6);\n','\n',char(10)),'2026-02-12 21:47:49');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(7,replace('\nALTER TABLE campaigns ADD COLUMN user_id TEXT;\n','\n',char(10)),replace('\nALTER TABLE campaigns DROP COLUMN user_id;\n','\n',char(10)),'2026-02-12 21:47:49');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(8,replace('CREATE TABLE campaign_comments (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  campaign_id INTEGER NOT NULL,\n  user_id TEXT NOT NULL,\n  user_name TEXT NOT NULL,\n  user_avatar TEXT,\n  content TEXT NOT NULL,\n  parent_id INTEGER,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_campaign_comments_campaign ON campaign_comments(campaign_id);\nCREATE INDEX idx_campaign_comments_parent ON campaign_comments(parent_id);','\n',char(10)),replace('DROP INDEX idx_campaign_comments_parent;\nDROP INDEX idx_campaign_comments_campaign;\nDROP TABLE campaign_comments;','\n',char(10)),'2026-02-12 21:47:49');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(9,replace('\nCREATE TABLE user_profiles (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL UNIQUE,\n  role TEXT NOT NULL,\n  document_type TEXT NOT NULL,\n  document_number TEXT NOT NULL,\n  company_name TEXT,\n  phone TEXT,\n  is_onboarding_complete BOOLEAN DEFAULT 0,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_user_profiles_user_id ON user_profiles(user_id);\n','\n',char(10)),replace('\nDROP INDEX idx_user_profiles_user_id;\nDROP TABLE user_profiles;\n','\n',char(10)),'2026-02-12 21:47:49');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(10,replace('-- Projects: submitted by capitadores\nCREATE TABLE projects (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  \n  -- Pre-registration fields\n  responsible_name TEXT NOT NULL,\n  email TEXT NOT NULL,\n  whatsapp TEXT NOT NULL,\n  project_name TEXT NOT NULL,\n  document_type TEXT NOT NULL,\n  website TEXT,\n  category TEXT NOT NULL,\n  funding_range TEXT NOT NULL,\n  stage TEXT NOT NULL,\n  \n  -- Full submission fields (nullable until filled)\n  document_number TEXT,\n  company_name TEXT,\n  address TEXT,\n  legal_representative TEXT,\n  \n  -- About the business\n  short_description TEXT,\n  full_description TEXT,\n  problem_solution TEXT,\n  revenue_model TEXT,\n  target_market TEXT,\n  competitive_advantage TEXT,\n  \n  -- Traction\n  current_revenue TEXT,\n  growth_info TEXT,\n  key_metrics TEXT,\n  team_info TEXT,\n  \n  -- Offer proposal\n  min_goal REAL,\n  max_goal REAL,\n  deadline_date DATE,\n  target_valuation TEXT,\n  equity_offered TEXT,\n  use_of_funds TEXT,\n  \n  -- Documents (JSON with file URLs)\n  pitch_deck_url TEXT,\n  social_contract_url TEXT,\n  cap_table_url TEXT,\n  financial_report_url TEXT,\n  other_docs_url TEXT,\n  \n  -- Status: draft, submitted, in_review, approved, rejected\n  status TEXT DEFAULT ''draft'',\n  rejection_reason TEXT,\n  submission_progress INTEGER DEFAULT 0,\n  \n  -- Timestamps\n  submitted_at DATETIME,\n  reviewed_at DATETIME,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_projects_user_id ON projects(user_id);\nCREATE INDEX idx_projects_status ON projects(status);\n\n-- Offers: public offerings created from approved projects\nCREATE TABLE offers (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  project_id INTEGER NOT NULL,\n  \n  -- Public info\n  title TEXT NOT NULL,\n  slug TEXT NOT NULL UNIQUE,\n  short_description TEXT NOT NULL,\n  full_description TEXT NOT NULL,\n  image_url TEXT,\n  category TEXT NOT NULL,\n  \n  -- Funding\n  min_goal REAL NOT NULL,\n  max_goal REAL NOT NULL,\n  current_amount REAL DEFAULT 0,\n  investors_count INTEGER DEFAULT 0,\n  min_investment REAL DEFAULT 1000,\n  \n  -- Dates\n  start_date DATE NOT NULL,\n  end_date DATE NOT NULL,\n  \n  -- Offer details\n  valuation TEXT,\n  equity_offered TEXT,\n  use_of_funds TEXT,\n  risks TEXT,\n  \n  -- Documents (public)\n  public_docs TEXT,\n  \n  -- Status: active, closed_success, closed_fail\n  status TEXT DEFAULT ''active'',\n  closed_at DATETIME,\n  \n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_offers_status ON offers(status);\nCREATE INDEX idx_offers_project_id ON offers(project_id);\n\n-- Investments: user investments in offers\nCREATE TABLE investments (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  user_id TEXT NOT NULL,\n  offer_id INTEGER NOT NULL,\n  \n  amount REAL NOT NULL,\n  \n  -- Risk acknowledgment\n  risk_acknowledged_at DATETIME NOT NULL,\n  \n  -- Status: pending (waiting for offer conclusion), released (tokens), refunded\n  status TEXT DEFAULT ''pending'',\n  \n  -- Payment (simulated)\n  payment_method TEXT,\n  payment_id TEXT,\n  paid_at DATETIME,\n  \n  -- Token info (simulated)\n  token_amount REAL,\n  token_released_at DATETIME,\n  refunded_at DATETIME,\n  \n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_investments_user_id ON investments(user_id);\nCREATE INDEX idx_investments_offer_id ON investments(offer_id);\nCREATE INDEX idx_investments_status ON investments(status);\n\n-- Token Jobs: placeholder for Hathor integration\nCREATE TABLE token_jobs (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  offer_id INTEGER NOT NULL,\n  investment_id INTEGER NOT NULL,\n  user_id TEXT NOT NULL,\n  \n  -- Job status: pending, ready, sent, failed\n  status TEXT DEFAULT ''pending'',\n  \n  -- Future Hathor fields\n  provider TEXT DEFAULT ''simulated'',\n  tx_id TEXT,\n  token_amount REAL,\n  \n  error_message TEXT,\n  \n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_token_jobs_offer_id ON token_jobs(offer_id);\nCREATE INDEX idx_token_jobs_status ON token_jobs(status);\n\n-- Messages: communication between Kate and capitadores\nCREATE TABLE messages (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  project_id INTEGER NOT NULL,\n  \n  -- Sender: ''admin'' or user_id\n  sender_type TEXT NOT NULL,\n  sender_id TEXT NOT NULL,\n  sender_name TEXT NOT NULL,\n  \n  content TEXT NOT NULL,\n  is_read BOOLEAN DEFAULT 0,\n  \n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_messages_project_id ON messages(project_id);\n\n-- Offer updates (news/progress)\nCREATE TABLE offer_updates (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  offer_id INTEGER NOT NULL,\n  \n  title TEXT NOT NULL,\n  content TEXT NOT NULL,\n  \n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_offer_updates_offer_id ON offer_updates(offer_id);\n','\n',char(10)),replace('DROP INDEX idx_offer_updates_offer_id;\nDROP TABLE offer_updates;\n\nDROP INDEX idx_messages_project_id;\nDROP TABLE messages;\n\nDROP INDEX idx_token_jobs_status;\nDROP INDEX idx_token_jobs_offer_id;\nDROP TABLE token_jobs;\n\nDROP INDEX idx_investments_status;\nDROP INDEX idx_investments_offer_id;\nDROP INDEX idx_investments_user_id;\nDROP TABLE investments;\n\nDROP INDEX idx_offers_project_id;\nDROP INDEX idx_offers_status;\nDROP TABLE offers;\n\nDROP INDEX idx_projects_status;\nDROP INDEX idx_projects_user_id;\nDROP TABLE projects;\n','\n',char(10)),'2026-02-12 21:47:49');
