INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(29,replace('\n-- Projeto de teste para produção\nINSERT INTO projects (\n  user_id,\n  responsible_name,\n  email,\n  whatsapp,\n  project_name,\n  document_type,\n  website,\n  category,\n  funding_range,\n  stage,\n  document_number,\n  company_name,\n  address,\n  short_description,\n  full_description,\n  problem_solution,\n  revenue_model,\n  target_market,\n  min_goal,\n  max_goal,\n  deadline_date,\n  target_valuation,\n  equity_offered,\n  use_of_funds,\n  status,\n  submission_progress,\n  token_uid,\n  token_symbol,\n  token_tx_hash,\n  total_tokens,\n  escrow_address,\n  is_blockchain_verified,\n  fundraising_started_at,\n  current_raised,\n  created_at,\n  updated_at\n) VALUES (\n  ''admin_test'',\n  ''Equipe Kate'',\n  ''contato@kate.com.br'',\n  ''11999999999'',\n  ''Kate Teste - Projeto Piloto'',\n  ''cnpj'',\n  ''https://kate.mocha.app'',\n  ''Tecnologia'',\n  ''ate_500k'',\n  ''mvp'',\n  ''00.000.000/0001-00'',\n  ''Kate Investimentos LTDA'',\n  ''São Paulo, SP'',\n  ''Projeto piloto para validação do fluxo de tokenização e distribuição de tokens na plataforma Kate.'',\n  ''Este é um projeto de teste para validar o fluxo completo de investimento, incluindo: reserva de cotas, confirmação de pagamento pelo admin, distribuição de tokens do escrow para investidores e emissão de NFT comprobatório.'',\n  ''Validar o fluxo de tokenização em ambiente de produção.'',\n  ''Plataforma de equity crowdfunding tokenizado.'',\n  ''Investidores e empresas em crescimento.'',\n  1000,\n  1000,\n  ''2025-12-31'',\n  ''R$ 100.000'',\n  ''1%'',\n  ''100% para validação técnica'',\n  ''fundraising'',\n  100,\n  ''SIM_TOKEN_KATE_TESTE_001'',\n  ''KATE'',\n  ''SIM_TX_TOKEN_CREATE_001'',\n  1,\n  ''SIM_ESCROW_ADDRESS_001'',\n  1,\n  CURRENT_TIMESTAMP,\n  0,\n  CURRENT_TIMESTAMP,\n  CURRENT_TIMESTAMP\n);\n\n-- Oferta ativa para o projeto\nINSERT INTO offers (\n  project_id,\n  title,\n  slug,\n  short_description,\n  full_description,\n  image_url,\n  category,\n  min_goal,\n  max_goal,\n  current_amount,\n  investors_count,\n  min_investment,\n  start_date,\n  end_date,\n  valuation,\n  equity_offered,\n  use_of_funds,\n  risks,\n  status,\n  created_at,\n  updated_at\n) VALUES (\n  (SELECT id FROM projects WHERE project_name = ''Kate Teste - Projeto Piloto''),\n  ''Kate Teste - Validação de Fluxo'',\n  ''kate-teste-validacao'',\n  ''Projeto piloto para validação do fluxo completo de tokenização e distribuição na plataforma Kate.'',\n  ''Este projeto permite testar o fluxo completo: investimento → confirmação de pagamento → distribuição de tokens → emissão de NFT. Apenas 1 cota disponível de R$1.000.'',\n  ''https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800'',\n  ''Tecnologia'',\n  1000,\n  1000,\n  0,\n  0,\n  1000,\n  DATE(''now''),\n  ''2025-12-31'',\n  ''R$ 100.000'',\n  ''1%'',\n  ''100% para validação técnica da plataforma'',\n  ''Este é um projeto de teste. Não invista valores reais.'',\n  ''active'',\n  CURRENT_TIMESTAMP,\n  CURRENT_TIMESTAMP\n);\n\n-- Evento de início de captação\nINSERT INTO project_events (\n  project_id,\n  event_type,\n  title,\n  description,\n  created_at,\n  updated_at\n) VALUES (\n  (SELECT id FROM projects WHERE project_name = ''Kate Teste - Projeto Piloto''),\n  ''fundraising_started'',\n  ''Captação Iniciada'',\n  ''Projeto de teste configurado para validação do fluxo de tokenização.'',\n  CURRENT_TIMESTAMP,\n  CURRENT_TIMESTAMP\n);\n\n-- Configurações da plataforma\nINSERT OR IGNORE INTO platform_config (config_key, config_value, created_at, updated_at)\nVALUES (''bank_name'', ''Banco Kate'', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);\n\nINSERT OR IGNORE INTO platform_config (config_key, config_value, created_at, updated_at)\nVALUES (''bank_agency'', ''0001'', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);\n\nINSERT OR IGNORE INTO platform_config (config_key, config_value, created_at, updated_at)\nVALUES (''bank_account'', ''12345-6'', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);\n\nINSERT OR IGNORE INTO platform_config (config_key, config_value, created_at, updated_at)\nVALUES (''pix_key'', ''contato@kate.com.br'', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);\n\nINSERT OR IGNORE INTO platform_config (config_key, config_value, created_at, updated_at)\nVALUES (''pix_name'', ''Kate Investimentos'', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);\n','\n',char(10)),replace('\nDELETE FROM platform_config WHERE config_key IN (''bank_name'', ''bank_agency'', ''bank_account'', ''pix_key'', ''pix_name'');\nDELETE FROM project_events WHERE project_id = (SELECT id FROM projects WHERE project_name = ''Kate Teste - Projeto Piloto'');\nDELETE FROM offers WHERE slug = ''kate-teste-validacao'';\nDELETE FROM projects WHERE project_name = ''Kate Teste - Projeto Piloto'';\n','\n',char(10)),'2026-02-19 23:42:00');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(30,replace('-- Corrigir datas da oferta de teste para permitir captação\nUPDATE offers \nSET start_date = ''2025-01-01'', \n    end_date = ''2025-12-31'',\n    status = ''active''\nWHERE slug = ''kate-teste-validacao'';\n\n-- Garantir que o projeto também está com status correto\nUPDATE projects \nSET status = ''fundraising''\nWHERE id = 10;','\n',char(10)),replace('UPDATE offers \nSET start_date = ''2026-02-19'', \n    end_date = ''2025-12-31''\nWHERE slug = ''kate-teste-validacao'';','\n',char(10)),'2026-02-20 00:30:14');
