INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(32,replace('-- Projeto de Teste em Produção - Blockchain Real\n-- Status ''approved'' para que o admin possa iniciar captação via API Hathor real\n\nINSERT INTO projects (\n  user_id,\n  responsible_name,\n  email,\n  whatsapp,\n  project_name,\n  document_type,\n  document_number,\n  company_name,\n  website,\n  category,\n  funding_range,\n  stage,\n  address,\n  legal_representative,\n  short_description,\n  full_description,\n  problem_solution,\n  revenue_model,\n  target_market,\n  competitive_advantage,\n  current_revenue,\n  growth_info,\n  key_metrics,\n  team_info,\n  min_goal,\n  max_goal,\n  deadline_date,\n  target_valuation,\n  equity_offered,\n  use_of_funds,\n  status,\n  submission_progress,\n  submitted_at,\n  reviewed_at,\n  created_at,\n  updated_at\n) VALUES (\n  ''admin-test-user'',\n  ''Kate Admin'',\n  ''admin@kate.com.br'',\n  ''11999999999'',\n  ''Kate Token Test 2026'',\n  ''PJ'',\n  ''12345678000199'',\n  ''Kate Crowdfunding Ltda'',\n  ''https://kate.mocha.app'',\n  ''Tecnologia'',\n  ''1000-5000'',\n  ''MVP'',\n  ''São Paulo, SP'',\n  ''Kate Admin'',\n  ''Projeto de teste para validar fluxo completo de tokenização com API Hathor real em produção.'',\n  ''Este é um projeto de teste criado para validar todo o fluxo de investimento, tokenização e emissão de NFT usando a API Hathor headless real. O objetivo é garantir que todos os processos funcionem corretamente em ambiente de produção antes de projetos reais.'',\n  ''Validação completa do fluxo de tokenização blockchain.'',\n  ''Plataforma de equity crowdfunding.'',\n  ''Investidores e empresas.'',\n  ''Integração completa com Hathor Network.'',\n  ''Em testes'',\n  ''Projeto piloto'',\n  ''Validação blockchain'',\n  ''Equipe Kate'',\n  1000,\n  1000,\n  ''2026-12-31'',\n  ''R$ 10.000'',\n  ''10%'',\n  ''100% para validação técnica'',\n  ''approved'',\n  100,\n  ''2026-01-15 10:00:00'',\n  ''2026-01-15 12:00:00'',\n  CURRENT_TIMESTAMP,\n  CURRENT_TIMESTAMP\n);\n\n-- Criar oferta associada ao projeto (precisa do ID do projeto inserido)\n-- Usando subquery para pegar o ID do projeto recém-criado\nINSERT INTO offers (\n  project_id,\n  title,\n  slug,\n  short_description,\n  full_description,\n  image_url,\n  category,\n  min_goal,\n  max_goal,\n  current_amount,\n  investors_count,\n  min_investment,\n  start_date,\n  end_date,\n  valuation,\n  equity_offered,\n  use_of_funds,\n  risks,\n  status,\n  created_at,\n  updated_at\n) VALUES (\n  (SELECT id FROM projects WHERE project_name = ''Kate Token Test 2026'' ORDER BY id DESC LIMIT 1),\n  ''Kate Token Test 2026'',\n  ''kate-token-test-2026'',\n  ''Projeto de teste para validar fluxo completo de tokenização com API Hathor real.'',\n  ''Este é um projeto de teste criado para validar todo o fluxo de investimento, tokenização e emissão de NFT usando a API Hathor headless real em produção.'',\n  ''https://019c104a-6f56-7035-a238-879c29552414.mochausercontent.com/Kate-Equity-Crowdfunding.png'',\n  ''Tecnologia'',\n  1000,\n  1000,\n  0,\n  0,\n  1000,\n  ''2026-01-01'',\n  ''2026-12-31'',\n  ''R$ 10.000'',\n  ''10%'',\n  ''100% para validação técnica'',\n  ''Projeto de teste - sem riscos reais.'',\n  ''draft'',\n  CURRENT_TIMESTAMP,\n  CURRENT_TIMESTAMP\n);','\n',char(10)),replace('DELETE FROM offers WHERE slug = ''kate-token-test-2026'';\nDELETE FROM projects WHERE project_name = ''Kate Token Test 2026'';','\n',char(10)),'2026-02-20 14:20:59');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(34,replace('CREATE TABLE admin_sessions (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  email TEXT NOT NULL,\n  token TEXT NOT NULL UNIQUE,\n  expires_at TIMESTAMP NOT NULL,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_admin_sessions_token ON admin_sessions(token);\nCREATE INDEX idx_admin_sessions_expires ON admin_sessions(expires_at);','\n',char(10)),replace('DROP INDEX idx_admin_sessions_expires;\nDROP INDEX idx_admin_sessions_token;\nDROP TABLE admin_sessions;','\n',char(10)),'2026-02-20 22:45:19');
