INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(36,replace('-- Projeto de teste para produção\nINSERT INTO projects (\n  user_id,\n  responsible_name,\n  email,\n  whatsapp,\n  project_name,\n  document_type,\n  category,\n  funding_range,\n  stage,\n  document_number,\n  company_name,\n  short_description,\n  full_description,\n  problem_solution,\n  revenue_model,\n  target_market,\n  min_goal,\n  max_goal,\n  deadline_date,\n  target_valuation,\n  equity_offered,\n  use_of_funds,\n  status,\n  submission_progress,\n  submitted_at\n) VALUES (\n  ''admin'',\n  ''Kate Investimentos'',\n  ''contato@kate.com.br'',\n  ''11999999999'',\n  ''Kate Teste Blockchain'',\n  ''pj'',\n  ''Fintech'',\n  ''1000-5000'',\n  ''mvp'',\n  ''00000000000191'',\n  ''Kate Investimentos LTDA'',\n  ''Projeto de teste para validar o fluxo completo de investimento com NFTs e tokens reais na blockchain Hathor.'',\n  ''Este é um projeto de teste criado para validar toda a integração com a blockchain Hathor, incluindo criação de NFTs de projeto, emissão de tokens, distribuição para investidores e registro de propriedade.'',\n  ''Validar o fluxo completo de equity crowdfunding tokenizado antes do lançamento oficial da plataforma.'',\n  ''Plataforma de equity crowdfunding com taxas sobre captações bem-sucedidas.'',\n  ''Startups e investidores brasileiros interessados em equity crowdfunding tokenizado.'',\n  1000,\n  1000,\n  ''2026-12-31'',\n  ''R$ 1.000'',\n  ''1%'',\n  ''100% para testes de integração blockchain'',\n  ''approved'',\n  100,\n  CURRENT_TIMESTAMP\n);\n\n-- Oferta correspondente\nINSERT INTO offers (\n  project_id,\n  title,\n  slug,\n  short_description,\n  full_description,\n  category,\n  min_goal,\n  max_goal,\n  min_investment,\n  start_date,\n  end_date,\n  valuation,\n  equity_offered,\n  use_of_funds,\n  risks,\n  status\n) VALUES (\n  (SELECT id FROM projects WHERE project_name = ''Kate Teste Blockchain'' ORDER BY id DESC LIMIT 1),\n  ''Kate Teste Blockchain'',\n  ''kate-teste-blockchain'',\n  ''Projeto de teste para validar NFTs e tokens reais na Hathor'',\n  ''Este projeto foi criado para testar o fluxo completo de investimento com blockchain. Inclui criação de NFT do projeto, emissão de tokens, reserva em escrow, aprovação de pagamentos, distribuição de tokens e emissão de NFT de investidor.'',\n  ''Fintech'',\n  1000,\n  1000,\n  100,\n  ''2026-01-01'',\n  ''2026-12-31'',\n  ''R$ 1.000'',\n  ''1%'',\n  ''100% para validação técnica'',\n  ''Este é um projeto de teste. Não invista valores reais.'',\n  ''draft''\n);','\n',char(10)),replace('DELETE FROM offers WHERE slug = ''kate-teste-blockchain'';\nDELETE FROM projects WHERE project_name = ''Kate Teste Blockchain'';','\n',char(10)),'2026-02-23 20:35:17');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(37,replace('-- Projeto de teste para fluxo NFT completo\nINSERT INTO projects (\n  user_id,\n  responsible_name,\n  email,\n  whatsapp,\n  project_name,\n  document_type,\n  category,\n  funding_range,\n  stage,\n  document_number,\n  company_name,\n  short_description,\n  full_description,\n  min_goal,\n  max_goal,\n  deadline_date,\n  equity_offered,\n  status,\n  submitted_at,\n  submission_progress\n) VALUES (\n  ''6'',\n  ''Pedro Silva'',\n  ''pedro@pedro.io'',\n  ''11999999999'',\n  ''Kate Blockchain Test'',\n  ''cnpj'',\n  ''technology'',\n  ''R$1.000 - R$10.000'',\n  ''mvp'',\n  ''12.345.678/0001-99'',\n  ''Kate Blockchain LTDA'',\n  ''Projeto de teste para validar o fluxo completo de NFT e Tokens na blockchain Hathor.'',\n  ''Este projeto foi criado para testar o fluxo completo de aprovação, emissão de NFT, criação de tokens e distribuição para investidores.'',\n  1000,\n  1000,\n  ''2026-12-31'',\n  ''10%'',\n  ''pending_review'',\n  CURRENT_TIMESTAMP,\n  100\n);\n\n-- Oferta correspondente\nINSERT INTO offers (\n  project_id,\n  title,\n  slug,\n  short_description,\n  full_description,\n  category,\n  min_goal,\n  max_goal,\n  min_investment,\n  start_date,\n  end_date,\n  equity_offered,\n  status\n) VALUES (\n  (SELECT id FROM projects WHERE project_name = ''Kate Blockchain Test'' ORDER BY id DESC LIMIT 1),\n  ''Kate Blockchain Test'',\n  ''kate-blockchain-test'',\n  ''Projeto de teste para validar o fluxo completo de NFT e Tokens na blockchain Hathor.'',\n  ''Este projeto foi criado para testar o fluxo completo de aprovação, emissão de NFT, criação de tokens e distribuição para investidores.'',\n  ''technology'',\n  1000,\n  1000,\n  100,\n  ''2026-01-01'',\n  ''2026-12-31'',\n  ''10%'',\n  ''draft''\n);','\n',char(10)),replace('DELETE FROM offers WHERE slug = ''kate-blockchain-test'';\nDELETE FROM projects WHERE project_name = ''Kate Blockchain Test'';','\n',char(10)),