INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(38,replace('-- Projeto de teste para validação do fluxo completo blockchain em produção\nINSERT OR IGNORE INTO projects (\n  id, user_id, responsible_name, email, whatsapp, project_name, document_type, \n  category, funding_range, stage, short_description, full_description,\n  min_goal, max_goal, status, created_at, updated_at\n) VALUES (\n  100,\n  (SELECT user_id FROM user_profiles WHERE role = ''emissor'' LIMIT 1),\n  ''Kate Teste'',\n  ''teste@kate.com.br'',\n  ''11999999999'',\n  ''Kate - Teste Producao Hathor'',\n  ''cnpj'',\n  ''fintech'',\n  ''1000'',\n  ''mvp'',\n  ''Projeto de teste para validação da integração com blockchain Hathor'',\n  ''Este projeto permite testar o fluxo completo: aprovação (cria NFT do projeto), emissão de tokens, investimento e distribuição.'',\n  1000, 1000,\n  ''pending_review'',\n  datetime(''now''),\n  datetime(''now'')\n);\n\n-- Oferta vinculada ao projeto de teste\nINSERT OR IGNORE INTO offers (\n  id, project_id, slug, title, short_description, full_description,\n  image_url, category, min_goal, max_goal, min_investment,\n  start_date, end_date, status, created_at, updated_at\n) VALUES (\n  100,\n  100,\n  ''kate-teste-producao-hathor'',\n  ''Kate - Teste Producao Hathor'',\n  ''Validação completa do fluxo blockchain'',\n  ''Este projeto permite testar o fluxo completo: aprovação (cria NFT do projeto), emissão de tokens, investimento e distribuição.'',\n  ''https://019c104a-6f56-7035-a238-879c29552414.mochausercontent.com/Kate-Equity-Crowdfunding.png'',\n  ''fintech'',\n  1000, 1000, 100,\n  ''2026-01-01'', ''2026-12-31'',\n  ''draft'',\n  datetime(''now''),\n  datetime(''now'')\n);\n','\n',char(10)),replace('DELETE FROM offers WHERE id = 100;\nDELETE FROM projects WHERE id = 100;\n','\n',char(10)),'2026-02-23 21:09:47');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(39,replace('-- Projeto de teste Hathor para validação em produção\n-- Usa INSERT OR REPLACE para garantir criação mesmo se já existir\nINSERT OR REPLACE INTO projects (\n  id, user_id, responsible_name, email, whatsapp, project_name, document_type, \n  category, funding_range, stage, short_description, full_description,\n  min_goal, max_goal, status, created_at, updated_at\n) VALUES (\n  101,\n  COALESCE((SELECT user_id FROM user_profiles WHERE role = ''emissor'' LIMIT 1), ''admin''),\n  ''Kate Teste'',\n  ''teste@kate.com.br'',\n  ''11999999999'',\n  ''Kate Hathor Test'',\n  ''cnpj'',\n  ''fintech'',\n  ''1000'',\n  ''mvp'',\n  ''Projeto de teste blockchain'',\n  ''Teste do fluxo completo de NFT e tokens com a API Hathor.'',\n  1000, 1000,\n  ''pending_review'',\n  datetime(''now''),\n  datetime(''now'')\n);\n\nINSERT OR REPLACE INTO offers (\n  id, project_id, slug, title, short_description, full_description,\n  image_url, category, min_goal, max_goal, min_investment,\n  start_date, end_date, status, created_at, updated_at\n) VALUES (\n  101,\n  101,\n  ''kate-hathor-test'',\n  ''Kate Hathor Test'',\n  ''Teste blockchain Hathor'',\n  ''Projeto para validar integração com API Hathor.'',\n  ''https://019c104a-6f56-7035-a238-879c29552414.mochausercontent.com/Kate-Equity-Crowdfunding.png'',\n  ''fintech'',\n  1000, 1000, 100,\n  ''2026-01-01'', ''2026-12-31'',\n  ''draft'',\n  datetime(''now''),\n  datetime(''now'')\n);\n','\n',char(10)),replace('DELETE FROM offers WHERE id = 101;\nDELETE FROM projects WHERE id = 101;\n','\n',char(10)),'2026-02-23 21:14:41');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(40,replace('-- Insert test project for production testing\nINSERT INTO projects (\n  user_id,\n  responsible_name,\n  email,\n  whatsapp,\n  project_name,\n  document_type,\n  category,\n  funding_range,\n  stage,\n  short_description,\n  full_description,\n  problem_solution,\n  revenue_model,\n  target_market,\n  competitive_advantage,\n  min_goal,\n  max_goal,\n  deadline_date,\n  target_valuation,\n  equity_offered,\n  use_of_funds,\n  status,\n  submission_progress,\n  submitted_at,\n  created_at,\n  updated_at\n) VALUES (\n  ''1'',\n  ''Teste Hathor Flow'',\n  ''teste@kate.io'',\n  ''11999999999'',\n  ''EcoSmart - Energia Solar Comunitária'',\n  ''PJ'',\n  ''Energia'',\n  ''100000-500000'',\n  ''operacional'',\n  ''Plataforma de energia solar compartilhada para comunidades urbanas.'',\n  ''EcoSmart é uma startup que oferece energia solar compartilhada para moradores de apartamentos. Nosso modelo permite que pessoas que não podem instalar painéis solares em seus telhados tenham acesso a energia limpa e mais barata através de fazendas solares comunitárias.'',\n  ''Milhões de pessoas querem usar energia solar mas moram em apartamentos. A EcoSmart resolve isso criando fazendas solares e permitindo que qualquer pessoa alugue uma fração dos painéis.'',\n  ''Assinatura mensal baseada no consumo de energia. Margem de 15-20% sobre o custo da energia gerada.'',\n  ''Moradores de apartamentos em grandes cidades que buscam energia sustentável e economia na conta de luz.'',\n  ''Primeira plataforma no Brasil focada exclusivamente em energia solar para apartamentos, com app próprio para acompanhamento em tempo real.'',\n  50000,\n  100000,\n  ''2026-06-30'',\n  ''R$ 2.000.000'',\n  ''5%'',\n  ''Expansão da fazenda solar principal (60%), marketing e aquisição de clientes (30%), tecnologia e app (10%)'',\n  ''pending_review'',\n  100,\n  datetime(''now''),\n  datetime(''now''),\n  datetime(''now'')\n);','\n',char(10)),'DELETE FROM projects WHERE project_name = ''EcoSmart - Energia Solar Comunitária'' AND email = ''teste@kate.io'';','2026-02-26 22:01:43');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(41,replace('-- Projeto teste para fluxo completo NFT > Tokenização\nINSERT INTO projects (\n  user_id, responsible_name, email, whatsapp, project_name, \n  document_type, category, funding_range, stage,\n  short_description, min_goal, max_goal, status,\n  created_at, updated_at\n) VALUES (\n  ''1'',\n  ''Carlos Silva'',\n  ''carlos@greentech.io'',\n  ''11988887777'',\n  ''GreenTech - Mobilidade Sustentável'',\n  ''PJ'',\n  ''Tecnologia'',\n  ''50k-100k'',\n  ''MVP'',\n  ''Startup de veículos elétricos compartilhados para mobilidade urbana sustentável.'',\n  30000,\n  80000,\n  ''pending_review'',\n  CURRENT_TIMESTAMP,\n  CURRENT_TIMESTAMP\n);','\n',char(10)),'DELETE FROM projects WHERE project_name = ''GreenTech - Mobilidade Sustentável'';','2026-02-26 22:20:50');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(42,replace('\n-- Create test project pending approval (using existing admin user or system)\nINSERT INTO projects (\n  user_id,\n  responsible_name,\n  email,\n  whatsapp,\n  project_name,\n  document_type,\n  website,\n  category,\n  funding_range,\n  stage,\n  document_number,\n  company_name,\n  address,\n  short_description,\n  full_description,\n  problem_solution,\n  revenue_model,\n  target_market,\n  min_goal,\n  max_goal,\n  equity_offered,\n  target_valuation,\n  use_of_funds,\n  deadline_date,\n  status,\n  slug,\n  created_at,\n  updated_at\n) VALUES (\n  ''system-test'',\n  ''Maria Oliveira'',\n  ''contato@solartech.com.br'',\n  ''(11) 99999-8888'',\n  ''SolarTech - Energia Limpa para Todos'',\n  ''cnpj'',\n  ''https://solartech.com.br'',\n  ''Energia'',\n  ''50k-200k'',\n  ''growth'',\n  ''12.345.678/0001-90'',\n  ''SolarTech Energia Renovável Ltda'',\n  ''São Paulo, SP - Brasil'',\n  ''Startup de painéis solares residenciais com tecnologia inovadora de células fotovoltaicas de alta eficiência'',\n  ''A SolarTech desenvolve painéis solares de última geração com eficiência 40% superior aos modelos convencionais. Nossa tecnologia patenteada permite geração de energia mesmo em dias nublados, democratizando o acesso à energia solar para residências brasileiras. Já instalamos mais de 500 sistemas em São Paulo e buscamos expandir para todo o Brasil.'',\n  ''O Brasil tem um dos maiores potenciais solares do mundo, mas menos de 2% das residências utilizam energia solar. Nossa tecnologia resolve as barreiras de custo e eficiência.'',\n  ''Venda direta de sistemas + Assinatura de manutenção + Créditos de carbono'',\n  ''Residências classe média/alta em SP, RJ, MG e Sul do Brasil - mercado de R$ 15 bilhões/ano'',\n  50000,\n  200000,\n  ''8%'',\n  ''R$ 2.500.000'',\n  ''40% Expansão da produção, 30% Marketing e vendas, 20% P&D, 10% Capital de giro'',\n  ''2025-06-30'',\n  ''pending_review'',\n  ''solartech-energia-limpa'',\n  CURRENT_TIMESTAMP,\n  CURRENT_TIMESTAMP\n);\n','\n',char(10)),replace('\nDELETE FROM projects WHERE slug = ''solartech-energia-limpa'';\n','\n',char(10)),'2026-02-26 23:09:14');
