INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(54,replace('-- Clean all test data from production\n\n-- Delete all test investments and related data\nDELETE FROM investments;\nDELETE FROM token_jobs;\nDELETE FROM pix_payments;\nDELETE FROM blockchain_logs;\nDELETE FROM hathor_operations;\nDELETE FROM hathor_assets;\nDELETE FROM hathor_addresses;\nDELETE FROM notifications;\n\n-- Delete all test offers\nDELETE FROM offers;\n\n-- Delete all test projects and related data\nDELETE FROM projects;\nDELETE FROM project_events;\nDELETE FROM messages;\nDELETE FROM documents;\n\n-- Delete leads and other test data\nDELETE FROM leads;\n\n-- Clean campaign related tables (if any test data)\nDELETE FROM campaigns;\nDELETE FROM rewards;\nDELETE FROM pledges;\nDELETE FROM campaign_updates;\nDELETE FROM campaign_faqs;\nDELETE FROM campaign_comments;\n\n-- Delete all test users and profiles (except admins)\nDELETE FROM user_sessions;\nDELETE FROM user_profiles;\nDELETE FROM users;\n\n-- Create test investor account\n-- Password: Investidor123! (will be hashed by the app on first login reset if needed)\nINSERT INTO users (email, password, name, email_verified)\nVALUES (''investidor@teste.kate.capital'', ''$2a$10$LKVQn3FD4aJHQV6mYH8Xfu7V4GYV7Q8zRkJXxq5r5hL2F3mY6VK6O'', ''Investidor Teste'', 1);\n\nINSERT INTO user_profiles (user_id, role, document_type, document_number, name, email, phone, is_onboarding_complete, welcome_seen)\nVALUES (\n  (SELECT id FROM users WHERE email = ''investidor@teste.kate.capital''),\n  ''investidor'',\n  ''cpf'',\n  ''12345678901'',\n  ''Investidor Teste'',\n  ''investidor@teste.kate.capital'',\n  ''21999999999'',\n  1,\n  1\n);\n\n-- Create test captador account\nINSERT INTO users (email, password, name, email_verified)\nVALUES (''captador@teste.kate.capital'', ''$2a$10$LKVQn3FD4aJHQV6mYH8Xfu7V4GYV7Q8zRkJXxq5r5hL2F3mY6VK6O'', ''Captador Teste'', 1);\n\nINSERT INTO user_profiles (user_id, role, document_type, document_number, name, email, phone, is_onboarding_complete, welcome_seen)\nVALUES (\n  (SELECT id FROM users WHERE email = ''captador@teste.kate.capital''),\n  ''capitador'',\n  ''cpf'',\n  ''98765432100'',\n  ''Captador Teste'',\n  ''captador@teste.kate.capital'',\n  ''21988888888'',\n  1,\n  1\n);','\n',char(10)),replace('-- Remove test accounts\nDELETE FROM user_profiles WHERE email IN (''investidor@teste.kate.capital'', ''captador@teste.kate.capital'');\nDELETE FROM users WHERE email IN (''investidor@teste.kate.capital'', ''captador@teste.kate.capital'');','\n',char(10)),'2026-04-22 11:54:41');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(55,replace('-- Add blockchain choice column to projects\nALTER TABLE projects ADD COLUMN blockchain TEXT DEFAULT ''hathor'';\n\n-- Add Stellar columns to projects\nALTER TABLE projects ADD COLUMN stellar_asset_code TEXT;\nALTER TABLE projects ADD COLUMN stellar_asset_issuer TEXT;\nALTER TABLE projects ADD COLUMN stellar_tx_hash TEXT;\n\n-- Add Stellar keypair columns to user_profiles\nALTER TABLE user_profiles ADD COLUMN stellar_public_key TEXT;\nALTER TABLE user_profiles ADD COLUMN stellar_secret_key TEXT;\n\n-- Add blockchain and Stellar columns to investments\nALTER TABLE investments ADD COLUMN blockchain TEXT DEFAULT ''hathor'';\nALTER TABLE investments ADD COLUMN stellar_tx_hash TEXT;\nALTER TABLE investments ADD COLUMN stellar_trustline_tx TEXT;','\n',char(10)),replace('-- Remove Stellar columns from investments\nALTER TABLE investments DROP COLUMN stellar_trustline_tx;\nALTER TABLE investments DROP COLUMN stellar_tx_hash;\nALTER TABLE investments DROP COLUMN blockchain;\n\n-- Remove Stellar keypair from user_profiles\nALTER TABLE user_profiles DROP COLUMN stellar_secret_key;\nALTER TABLE user_profiles DROP COLUMN stellar_public_key;\n\n-- Remove Stellar columns from projects\nALTER TABLE projects DROP COLUMN stellar_tx_hash;\nALTER TABLE projects DROP COLUMN stellar_asset_issuer;\nALTER TABLE projects DROP COLUMN stellar_asset_code;\nALTER TABLE projects DROP COLUMN blockchain;','\n',char(10)),'2026-05-04 15:46:36');
CREATE TABLE campaigns (
id INTEGER PRIMARY KEY AUTOINCREMENT,
title TEXT NOT NULL,
short_description TEXT NOT NULL,
full_description TEXT NOT NULL,
image_url TEXT NOT NULL,
category TEXT NOT NULL,
goal_amount REAL NOT NULL,
current_amount REAL DEFAULT 0,
backers_count INTEGER DEFAULT 0,
end_date DATE NOT NULL,
creator_name TEXT NOT NULL,
creator_email TEXT,
creator_avatar TEXT,
is_featured BOOLEAN DEFAULT 0,
status TEXT DEFAULT 'active',
risks TEXT,
created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, user_id TEXT);
CREATE TABLE rewards (
id INTEGER PRIMARY KEY AUTOINCREMENT,
campaign_id INTEGER NOT NULL,
title TEXT NOT NULL,
description TEXT NOT NULL,
min_amount REAL NOT NULL,
estimated_delivery TEXT NOT NULL,
items_included TEXT NOT NULL,
limited_quantity INTEGER,
claimed_count INTEGER DEFAULT 0,
created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE pledges (
id INTEGER PRIMARY KEY AUTOINCREMENT,
campaign_id INTEGER NOT NULL,
reward_id INTEGER,
amount REAL NOT NULL,
backer_name TEXT NOT NULL,
backer_email TEXT NOT NULL,
status TEXT DEFAULT 'pending',
payment_id TEXT,
created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE campaign_updates (
id INTEGER PRIMARY KEY AUTOINCREMENT,
campaign_id INTEGER NOT NULL,
title TEXT NOT NULL,
content TEXT NOT NULL,
created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE campaign_faqs (
id INTEGER PRIMARY KEY AUTOINCREMENT,
campaign_id INTEGER NOT NULL,
question TEXT NOT NULL,
answer TEXT NOT NULL,
created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE campaign_comments (
id INTEGER PRIMARY KEY AUTOINCREMENT,
campaign_id INTEGER NOT NULL,
user_id TEXT NOT NULL,
user_name TEXT NOT NULL,
user_avatar TEXT,
content TEXT NOT NULL,
parent_id INTEGER,
created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE user_profiles (
id INTEGER PRIMARY KEY AUTOINCREMENT,
user_id TEXT NOT NULL UNIQUE,
role TEXT NOT NULL,
document_type TEXT NOT NULL,
document_number TEXT NOT NULL,
company_name TEXT,
phone TEXT,
is_onboarding_complete BOOLEAN DEFAULT 0,
created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
